def parse_app_spec(spec: str) -> Dict:
    """
    Format:
      app_name:vhost:user:password[:tags]
    Example:
      billing:/billing:billing_user:StrongPass123:management
    """
    parts = spec.split(":", 4)
    if len(parts) < 4:
        raise ValueError(f"Invalid app spec: {spec}")
    app_name, vhost, user, password = parts[:4]
    tags = parts[4] if len(parts) == 5 else ""
    return {"app_name": app_name, "vhost": vhost, "user": user, "password": password, "tags": tags}


